namespace sv_bb512ee3c347421f9a322ded63a4a91e.Models;

public class WizardData
{
    // Step 1 – Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been saved
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_bb512ee3c347421f9a322ded63a4a91e.Models;

namespace sv_bb512ee3c347421f9a322ded63a4a91e.Services;

/// <summary>
/// Singleton in-memory store keyed by a per-applicant cookie value.
/// Both SSR (layout) and Interactive Server (pages) resolve the same
/// instance and use the cookie value to isolate each applicant's data.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Save(string sessionId, WizardData data)
        => _store[sessionId] = data;
}

