using System.Collections.Concurrent;
using sv_bb512ee3c347421f9a322ded63a4a91e.Models;

namespace sv_bb512ee3c347421f9a322ded63a4a91e.Services;

/// <summary>
/// Singleton in-memory store keyed by a per-applicant cookie value.
/// Both SSR (layout) and Interactive Server (pages) resolve the same
/// instance and use the cookie value to isolate each applicant's data.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Save(string sessionId, WizardData data)
        => _store[sessionId] = data;
}

