@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpCtx
@inject sv_bb512ee3c347421f9a322ded63a4a91e.Services.WizardStateStore Store
@using sv_bb512ee3c347421f9a322ded63a4a91e.Models

@{
    var sessionId = HttpCtx.HttpContext?.Request.Cookies["WizardSession"] ?? "";
    var data = string.IsNullOrEmpty(sessionId) ? new WizardData() : Store.GetOrCreate(sessionId);
    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
}

<div class="container py-4">
    <h2 class="mb-3">Job Application</h2>

    <div class="d-flex mb-4 gap-2">
        @foreach (var step in steps)
        {
            var isCurrent = currentPath.Equals(step.Href, StringComparison.OrdinalIgnoreCase);
            var isCompleted = data.CompletedSteps.Contains(step.Number);

            <a href="@step.Href"
               class="btn @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary") flex-fill text-center">
                Step @step.Number: @step.Label
                @if (isCompleted) { <span>✓</span> }
            </a>
        }
    </div>

    <div class="mb-3">
        <div class="progress" style="height: 8px;">
            <div class="progress-bar" role="progressbar"
                 style="width: @(ProgressPercent(currentPath))%">
            </div>
        </div>
        <small class="text-muted">Step @CurrentStep(currentPath) of 4</small>
    </div>

    @Body
</div>

@code {
    private record StepInfo(int Number, string Label, string Href);

    private static readonly StepInfo[] steps =
    [
        new(1, "Personal Info", "/apply/personal-info"),
        new(2, "Experience",    "/apply/experience"),
        new(3, "References",    "/apply/references"),
        new(4, "Review",        "/apply/review"),
    ];

    private int CurrentStep(string path)
        => steps.FirstOrDefault(s => s.Href.Equals(path, StringComparison.OrdinalIgnoreCase))?.Number ?? 1;

    private int ProgressPercent(string path)
        => CurrentStep(path) * 25;
}

