@page "/apply/experience"
@layout sv_bb512ee3c347421f9a322ded63a4a91e.Components.Layout.WizardLayout
@rendermode InteractiveServer
@inject sv_bb512ee3c347421f9a322ded63a4a91e.Services.WizardStateStore Store
@inject NavigationManager Nav
@using sv_bb512ee3c347421f9a322ded63a4a91e.Models
@using Microsoft.AspNetCore.Components.Web

<PageTitle>Experience – Apply</PageTitle>
<h3>Work Experience</h3>

@for (var i = 0; i < jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="jobs[index].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary me-2" @onclick="AddJob">+ Add Job</button>

<hr />
<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private List<JobEntry> jobs = [];
    private string sessionId = "";

    protected override async Task OnInitializedAsync()
    {
        sessionId = await GetSessionId();
        var data = Store.GetOrCreate(sessionId);
        jobs = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();

        if (jobs.Count == 0) jobs.Add(new JobEntry());
    }

    private void AddJob() => jobs.Add(new JobEntry());
    private void RemoveJob(int i) { if (jobs.Count > 1) jobs.RemoveAt(i); }

    private void HandleNext()
    {
        var data = Store.GetOrCreate(sessionId);
        data.JobHistory = jobs.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
        data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }

    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpCtxAccessor { get; set; } = default!;
    private PersistingComponentStateSubscription? _sub;

    private async Task<string> GetSessionId()
    {
        if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var restored) && restored is not null)
            return restored;

        var id = HttpCtxAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("WizardSessionId", id);
            return Task.CompletedTask;
        });
        return id;
    }

    public void Dispose() => _sub?.Dispose();
}

