@page "/apply/review"
@layout sv_bb512ee3c347421f9a322ded63a4a91e.Components.Layout.WizardLayout
@rendermode InteractiveServer
@inject sv_bb512ee3c347421f9a322ded63a4a91e.Services.WizardStateStore Store
@inject NavigationManager Nav
@using sv_bb512ee3c347421f9a322ded63a4a91e.Models

<PageTitle>Review – Apply</PageTitle>
<h3>Review Your Application</h3>

@if (data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @data.Name</p>
        <p><strong>Email:</strong> @data.Email</p>
        <a href="/apply/personal-info" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (data.JobHistory.Count == 0)
        {
            <p class="text-muted">No jobs added.</p>
        }
        else
        {
            @foreach (var job in data.JobHistory)
            {
                <p>@job.Title at @job.Company (@job.Years years)</p>
            }
        }
        <a href="/apply/experience" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (data.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            @foreach (var r in data.References)
            {
                <p>@r.Name – @r.Email (@r.Relationship)</p>
            }
        }
        <a href="/apply/references" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <hr />
    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-outline-secondary">← Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    private WizardData? data;
    private string sessionId = "";
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        sessionId = await GetSessionId();
        data = Store.GetOrCreate(sessionId);
    }

    private void Submit()
    {
        data?.CompletedSteps.Add(4);
        submitted = true;
    }

    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpCtxAccessor { get; set; } = default!;
    private PersistingComponentStateSubscription? _sub;

    private async Task<string> GetSessionId()
    {
        if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var restored) && restored is not null)
            return restored;

        var id = HttpCtxAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("WizardSessionId", id);
            return Task.CompletedTask;
        });
        return id;
    }

    public void Dispose() => _sub?.Dispose();
}

