using sv_bb512ee3c347421f9a322ded63a4a91e.Components;
using sv_bb512ee3c347421f9a322ded63a4a91e.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateStore>();

var app = builder.Build();

// Assign a unique session cookie for each applicant so the singleton
// WizardStateStore can isolate their data.  Both the static SSR layout
// and the Interactive Server pages read this same cookie value.
app.Use(async (context, next) =>
{
    if (context.Request.Path.StartsWithSegments("/apply")
        && !context.Request.Cookies.ContainsKey("WizardSession"))
    {
        context.Response.Cookies.Append("WizardSession", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
    }
    await next();
});

